class Solution:
    def canIWin(self, maxChoosableInteger: int, desiredTotal: int) -> bool:
        if (maxChoosableInteger * (maxChoosableInteger + 1)) // 2 < desiredTotal:
            return False
        memo = {}
        def dfs(used, total):
            key = (used, total)
            if key in memo:
                return memo[key]
            for i in range(1, maxChoosableInteger + 1):
                if not (used & (1 << (i - 1))):
                    if total + i >= desiredTotal:
                        memo[key] = True
                        return True
                    if not dfs(used | (1 << (i - 1)), total + i):
                        memo[key] = True
                        return True
            memo[key] = False
            return False
        return dfs(0, 0)
